import React, { useContext, useEffect, useMemo, useState } from "react";
import { Alert, Button, Snackbar, TextField } from "@mui/material";
import MeetingRoomOutlinedIcon from "@mui/icons-material/MeetingRoomOutlined";
import EventNoteOutlinedIcon from "@mui/icons-material/EventNoteOutlined";
import PlayCircleOutlineOutlinedIcon from "@mui/icons-material/PlayCircleOutlineOutlined";
import HistoryOutlinedIcon from "@mui/icons-material/HistoryOutlined";
import VideoLibraryOutlinedIcon from "@mui/icons-material/VideoLibraryOutlined";
import withAdminAuth from "../utils/withAdminAuth";
import { AdminAuthContext } from "../contexts/AdminAuthContext";
import "../App.css";

function AdminDashboard() {
  const [scheduled, setScheduled] = useState([]);
  const [history, setHistory] = useState([]);
  const [recordingMeetingId, setRecordingMeetingId] = useState("");
  const [recordingCount, setRecordingCount] = useState(null);
  const [info, setInfo] = useState("");
  const [error, setError] = useState("");

  const { adminUser, logoutAdmin, getScheduledMeetings, getMeetingHistory, getRecordings } =
    useContext(AdminAuthContext);

  useEffect(() => {
    const load = async () => {
      try {
        const [scheduledData, historyData] = await Promise.all([
          getScheduledMeetings(),
          getMeetingHistory(),
        ]);
        setScheduled(Array.isArray(scheduledData) ? scheduledData : []);
        setHistory(Array.isArray(historyData) ? historyData : []);
      } catch (e) {
        setError(e?.response?.data?.message || "Unable to load dashboard data.");
      }
    };
    load();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const stats = useMemo(() => {
    const upcoming = scheduled.filter((m) => m?.status === "not_started").length;
    const active = scheduled.filter((m) => m?.status === "active").length;
    return {
      scheduled: scheduled.length,
      upcoming,
      active,
      history: history.length,
    };
  }, [history.length, scheduled]);

  const checkRecordings = async () => {
    const meetingId = recordingMeetingId.trim();
    if (!meetingId) {
      setError("Enter meeting ID first.");
      return;
    }

    try {
      const response = await getRecordings(meetingId, { page: 1, limit: 5 });
      const total = response?.pagination?.total ?? (response?.items || []).length;
      setRecordingCount(total);
      setInfo(`Meeting ${meetingId} has ${total} recording(s).`);
    } catch (e) {
      setRecordingCount(null);
      setError(e?.response?.data?.message || "Unable to load recordings.");
    }
  };

  return (
    <div className="adminDashboardPage">
      <header className="adminTopbar">
        <div>
          <p className="adminOverline">Admin Workspace</p>
          <h2>Zomeetix Console</h2>
          <small>{adminUser?.name || adminUser?.username || adminUser?.email}</small>
        </div>
        <Button variant="outlined" onClick={logoutAdmin}>
          Logout
        </Button>
      </header>

      <section className="adminStatGrid">
        <article className="adminStatCard">
          <EventNoteOutlinedIcon />
          <div>
            <h3>{stats.scheduled}</h3>
            <p>Total Scheduled</p>
          </div>
        </article>
        <article className="adminStatCard">
          <MeetingRoomOutlinedIcon />
          <div>
            <h3>{stats.upcoming}</h3>
            <p>Upcoming</p>
          </div>
        </article>
        <article className="adminStatCard">
          <PlayCircleOutlineOutlinedIcon />
          <div>
            <h3>{stats.active}</h3>
            <p>Active Now</p>
          </div>
        </article>
        <article className="adminStatCard">
          <HistoryOutlinedIcon />
          <div>
            <h3>{stats.history}</h3>
            <p>History Entries</p>
          </div>
        </article>
      </section>

      <section className="adminPanelGrid">
        <div className="adminBox">
          <h4>Upcoming Meetings</h4>
          {scheduled.length === 0 ? (
            <p>No meetings scheduled.</p>
          ) : (
            <div className="adminList">
              {scheduled.slice(0, 8).map((item) => (
                <div className="adminListRow" key={item.meetingId}>
                  <div>
                    <strong>{item.meetingId}</strong>
                    <p>{new Date(item?.schedule?.startAt || Date.now()).toLocaleString()}</p>
                  </div>
                  <span className={`statusBadge status-${item.status || "unknown"}`}>{item.status || "unknown"}</span>
                </div>
              ))}
            </div>
          )}
        </div>

        <div className="adminBox">
          <h4>Recording Lookup</h4>
          <p className="muted">Check recordings count for a meeting.</p>
          <div className="recordingLookup">
            <TextField
              label="Meeting ID"
              value={recordingMeetingId}
              onChange={(e) => setRecordingMeetingId(e.target.value)}
              size="small"
              fullWidth
            />
            <Button variant="contained" startIcon={<VideoLibraryOutlinedIcon />} onClick={checkRecordings}>
              Check
            </Button>
          </div>
          {recordingCount !== null ? (
            <p className="lookupResult">Recordings: {recordingCount}</p>
          ) : null}
        </div>
      </section>

      <Snackbar open={Boolean(error)} autoHideDuration={3000} onClose={() => setError("")}>
        <Alert severity="error" onClose={() => setError("")}>
          {error}
        </Alert>
      </Snackbar>
      <Snackbar open={Boolean(info)} autoHideDuration={2500} onClose={() => setInfo("")}>
        <Alert severity="success" onClose={() => setInfo("")}>
          {info}
        </Alert>
      </Snackbar>
    </div>
  );
}

export default withAdminAuth(AdminDashboard);
